1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const FIRST_INSURANCE_RATE = 0.1;
21	const PROCESSING_FEE = 5;
22	
23	const COMPONENT_TYPES = ["rune", "moonstone"];
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);
28	
29	const typeBasePremium = (type: string, count: number): number =>
30	  isComponent(type) && count === COMPONENT_BLOCK_SIZE
31	    ? COMPONENT_BLOCK_PREMIUM
32	    : count * BASE_PREMIUM[type];
33	
34	const countByType = (items: { type: string }[]): Map<string, number> => {
35	  const counts = new Map<string, number>();
36	  for (const item of items) {
37	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
38	  }
39	  return counts;
40	};
41	
42	const policyBasePremium = (items: { type: string }[]): number => {
43	  let total = 0;
44	  for (const [type, count] of countByType(items)) {
45	    total += typeBasePremium(type, count);
46	  }
47	  return total;
48	};
49	
50	const quotePremium = (step: QuoteStep): number => {
51	  const policyBase = policyBasePremium(step.items);
52	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
53	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
54	};
55	
56	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
57	  return {
58	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
59	  };
60	};
